/**
 * Look up a transition curve for a phoneme pair.
 * Returns the 8-frame curve if found, or null to fall back to rule-based blending.
 */
export function getTransitionCurve(fromPhoneme: string, toPhoneme: string): number[][] | null {
  const key = `${fromPhoneme}_${toPhoneme}`
  return TRANSITION_CURVES[key] ?? null
}

/**
 * Interpolate a band gain array from the transition curve at a given position.
 * @param curve The 8-frame transition curve
 * @param t Position in the transition (0.0 = start, 1.0 = end)
 * @returns Interpolated 10-band gain array
 */
export function interpolateTransition(curve: number[][], t: number): number[] {
  const clamped = Math.max(0, Math.min(1, t))
  const idx = clamped * (curve.length - 1)
  const lo = Math.floor(idx)
  const hi = Math.min(lo + 1, curve.length - 1)
  const frac = idx - lo

  const result: number[] = []
  for (let b = 0; b < 10; b++) {
    result.push(curve[lo][b] * (1 - frac) + curve[hi][b] * frac)
  }
  return result
}
